import{_ as i,o as a,c as o,a4 as t}from"./chunks/framework.Cqne-ChA.js";const b=JSON.parse('{"title":"Leveraging the ZOSLIB library","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/Zoslib.md","filePath":"Guides/Zoslib.md","lastUpdated":1760390648000}'),r={name:"Guides/Zoslib.md"};function s(n,e,l,p,h,d){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="leveraging-the-zoslib-library" tabindex="-1">Leveraging the ZOSLIB library <a class="header-anchor" href="#leveraging-the-zoslib-library" aria-label="Permalink to &quot;Leveraging the ZOSLIB library&quot;">​</a></h1><h2 id="what-is-zoslib" tabindex="-1">What is ZOSLIB? <a class="header-anchor" href="#what-is-zoslib" aria-label="Permalink to &quot;What is ZOSLIB?&quot;">​</a></h2><p><strong>ZOSLIB</strong> is a z/OS C/C++ library. It is an extended implementation of the z/OS LE C Runtime Library.</p><p>ZOSLIB implements the following:</p><ul><li>A subset of POSIX APIs that are not available in the LE C Runtime Library</li><li>Overrides for C open, pipe, and more for improved functionality with z/OS auto-conversion facilities.</li><li>EBCDIC &lt;-&gt; ASCII conversion C APIs</li><li>APIs for improved diagnostic reporting</li><li>and more!</li></ul><p>You can find more details at the <a href="https://github.com/ibmruntimes/zoslib/tree/zopen" target="_blank" rel="noreferrer">ZOSLIB github page</a>.</p><p>The corresponding <code>zopen</code> project lives <a href="https://github.com/zopencommunity/zoslibport" target="_blank" rel="noreferrer">here</a>.</p><h2 id="how-can-zoslib-help-my-project" tabindex="-1">How can ZOSLIB help my project? <a class="header-anchor" href="#how-can-zoslib-help-my-project" aria-label="Permalink to &quot;How can ZOSLIB help my project?&quot;">​</a></h2><p>As we continue to port projects to z/OS, we have come across many common issues. Rather than repeating the same patterns and duplicating the solutions on a per project basis, we decided to take a different approach. We decided to solve the issues by linking to an intermediary library, ZOSLIB.</p><p>ZOSLIB is an actively developed library that&#39;s currently being used by 20+ zopen community projects, including curl, git, bash and more.</p><p>ZOSLIB aims to automatically resolve the following types of issues:</p><ul><li>Tagging file descriptors which are not tagged appropriately via C open, mkstemp or pipe.</li><li>Missing POSIX/glibc function or types. (e.g. posix_spawn)</li><li>Missing header files. (e.g. sys/mount.h)</li></ul><p>As an example, the C <code>open</code> function has been overridden to automatically tag new files as ASCII, and similarly for C <code>pipe</code> and <code>mkstemp</code>. When zoslib is added to your project, in the case of C <code>open</code> function, all references to open are mapped to a new zoslib <code>__open_ascii</code> function (defined <a href="https://github.com/ibmruntimes/zoslib/blob/zopen/src/zos-io.cc#L720" target="_blank" rel="noreferrer">here</a>), which implements this auto-tagging logic.</p><h2 id="how-do-i-use-zoslib" tabindex="-1">How do I use zoslib? <a class="header-anchor" href="#how-do-i-use-zoslib" aria-label="Permalink to &quot;How do I use zoslib?&quot;">​</a></h2><p>Very easily!</p><p>Through the zopen framework, all you need to do is to add <code>zoslib</code> as a dependency as follows:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ZOPEN_DEPS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;curl gzip tar make zoslib&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Here&#39;s a <a href="https://github.com/zopencommunity/curlport/blob/main/buildenv#L3" target="_blank" rel="noreferrer">real example</a> where the curl port added zoslib as a dependency.</p><h3 id="how-does-this-work" tabindex="-1">How does this work? <a class="header-anchor" href="#how-does-this-work" aria-label="Permalink to &quot;How does this work?&quot;">​</a></h3><p>This works because ZOSLIB exposes a set of environment variable flags via it&#39;s <a href="https://github.com/zopencommunity/zoslibport/blob/main/buildenv#L35" target="_blank" rel="noreferrer">buildenv</a>. These environment variable will automatically be added to your project when it is included as a dependency. They instruct the compiler to pick up the header files and link to the appropriate zoslib static archive.</p><h2 id="how-do-i-contribute" tabindex="-1">How do I contribute? <a class="header-anchor" href="#how-do-i-contribute" aria-label="Permalink to &quot;How do I contribute?&quot;">​</a></h2><p>We are happy to accept community code changes! Open a pull request at <a href="https://github.com/ibmruntimes/zoslib/pulls" target="_blank" rel="noreferrer">https://github.com/ibmruntimes/zoslib/pulls</a></p>',22)])])}const u=i(r,[["render",s]]);export{b as __pageData,u as default};
